// ---- ALTERNATIVE: Even better — use TypeORM QueryBuilder (it IS flexible enough) ----

async function searchProductsWithQueryBuilder(
  connection: Connection,
  filters: ProductSearchQuery
) {
  const qb = connection
    .getRepository(Product)
    .createQueryBuilder("product");

  if (filters.name) {
    qb.andWhere("product.name ILIKE :name", { name: `%${filters.name}%` });
  }

  if (filters.category) {
    qb.andWhere("product.category = :category", {
      category: filters.category,
    });
  }

  if (filters.brand) {
    qb.andWhere("product.brand = :brand", { brand: filters.brand });
  }

  if (filters.minPrice) {
    const minPrice = parseFloat(filters.minPrice);
    if (!isNaN(minPrice) && minPrice >= 0) {
      qb.andWhere("product.price >= :minPrice", { minPrice });
    }
  }

  if (filters.maxPrice) {
    const maxPrice = parseFloat(filters.maxPrice);
    if (!isNaN(maxPrice) && maxPrice >= 0) {
      qb.andWhere("product.price <= :maxPrice", { maxPrice });
    }
  }

  if (filters.minRating) {
    const minRating = parseFloat(filters.minRating);
    if (!isNaN(minRating) && minRating >= 0 && minRating <= 5) {
      qb.andWhere("product.rating >= :minRating", { minRating });
    }
  }

  if (filters.inStock !== undefined) {
    qb.andWhere("product.in_stock = :inStock", {
      inStock: filters.inStock === "true",
    });
  }

  const sortColumn =
    ALLOWED_SORT_COLUMNS[filters.sortBy || ""] || "product.created_at";
  const sortOrder: "ASC" | "DESC" = ALLOWED_SORT_ORDERS.has(
    (filters.sortOrder || "").toUpperCase()
  )
    ? ((filters.sortOrder!.toUpperCase()) as "ASC" | "DESC")
    : "DESC";

  qb.orderBy(sortColumn, sortOrder);

  const limit = Math.min(
    Math.max(parseInt(filters.limit || "20", 10) || 20, 1),
    100
  );
  const page = Math.max(parseInt(filters.page || "1", 10) || 1, 1);

  qb.skip((page - 1) * limit).take(limit);

  const [products, total] = await qb.getManyAndCount();

  return { products, total, page, limit };
}

